import { createContext, useState, useContext, useEffect } from "react";
import axios from "axios";
import { jwtDecode } from "jwt-decode";
import { toast } from "react-toastify";

// Create context
const AuthContext = createContext();

// Axios global config (adjust baseURL for your backend)
axios.defaults.baseURL = "http://localhost:5000"; // ✅ your backend server URL
axios.defaults.headers.post["Content-Type"] = "application/json";

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [tokens, setTokens] = useState(null);

  // ✅ Restore user if already logged in
  useEffect(() => {
    const storedTokens = localStorage.getItem("authTokens");
    if (storedTokens) {
      try {
        const parsed = JSON.parse(storedTokens);
        const decoded = jwtDecode(parsed.access);
        setUser(decoded);
        setTokens(parsed);
      } catch (err) {
        console.error("Stored token invalid, clearing...", err);
        localStorage.removeItem("authTokens");
      }
    }
  }, []);

  // ✅ Login function
  const login = async (email, password) => {
    try {
      const res = await axios.post("/api/auth/login", { email, password });

      // Debug log to see backend response
      console.log("Login response:", res.data);

      const { access, refresh, token } = res.data;

      // ✅ Determine which token field is valid (backend may use different names)
      const jwtToken = access || token;

      if (!jwtToken) {
        toast.error("No valid access token received from server!");
        return;
      }

      // ✅ Decode token to get user info
      const decoded = jwtDecode(jwtToken);
      console.log("Decoded token:", decoded);

      setUser(decoded);
      setTokens(res.data);
      localStorage.setItem("authTokens", JSON.stringify(res.data));
      toast.success("Login successful!");
    } catch (err) {
      console.error("Login error:", err);
      toast.error(
        err.response?.data?.message || "Login failed. Please try again."
      );
    }
  };

  // ✅ Logout function
  const logout = () => {
    localStorage.removeItem("authTokens");
    setUser(null);
    setTokens(null);
    toast.info("Logged out successfully!");
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, tokens }}>
      {children}
    </AuthContext.Provider>
  );
};

// ✅ Custom hook to use the auth context
export const useAuth = () => useContext(AuthContext);
